self.addEventListener('message', function(e) {
  if(e.data === "<<{START}>>") self.postMessage( "<<{STARTED}>>" );
  else self.postMessage( sentenceBreakdown(e.data) );
}, false);


function sentenceBreakdown(text) {
  return text.split(/([!?:,."]+)/gi)
      .filter(function(a) {
         return ( a !== "" );
       })
      .map(function(a) {
        
        if(/[!?:,."]+/gi.test(a)) {
          return a;
        } else {
          return modern2old(a);
        }
        
      }).join("");
}


function modern2old(text) { 

  var words = text.replace(/[!?:,."]+/gi,"").split(" ");
  var result = "";
  
  // handle 0 or 1 words cases
  if(words.length === 0) return "";
  if(words.length === 1) {
        if(words[0] === " ") return " ";
        if(words[0] === "") return "";
        var old = m2o[words[0].toLowerCase()];
        if(old) {
          return old[ Math.floor(Math.random()*old.length) ];
        } else {
          return "[" + words[0] + "]";
        }
  }
  
  // handle 2+ words cases:
  for(var i = 0; i < words.length-1; i++) {  //length-1 because we're doing word pairs too - we check the last word after this loop
    
    if(words[i] === " ") result += " ";
    if(words[i] === "") result += "";
    
    var pair = words[i] + " " + words[i+1];
    var old = m2o[pair.toLowerCase()];
    if(old) {
      result += old[ Math.floor(Math.random()*old.length) ];
      i++;
    } else {
        old = m2o[words[i].toLowerCase()];
        if(old) {
          result += " " + old[ Math.floor(Math.random()*old.length) ];
        } else {
          result += " [" + words[i] + "]";
        }
    }
  }
  
  // handle last word
  if(words[words.length-1] === " ") { result += " "; }
  else if(words[words.length-1] === "") { result += ""; }
  else {
    var old = m2o[words[words.length-1]];
    if(old) {
      result += " " + old[ Math.floor(Math.random()*old.length) ];
    } else {
      result += " [" + words[words.length-1] + "]";
    }
  }
  
  return result.trim(); 
  
}

